    public HealthcareServiceResponse PrescribeMedication(string patientId, Medication medication)
    {
        string transactionId = GenerateTransactionId();
        try
        {
            ValidateCallerAuthorization("PrescribeMedication");
            _auditLogger.LogAccess("PrescribeMedication", GetCallerIdentity(), transactionId);

            if (string.IsNullOrEmpty(patientId))
                ThrowFault("INVALID_REQUEST", "PatientId is required.");

            if (medication == null)
                ThrowFault("INVALID_REQUEST", "Medication details are required.");

            // Check for drug interactions with existing medications
            var warnings = CheckDrugInteractions(patientId, medication);

            lock (LockObj)
            {
                if (!PatientStore.ContainsKey(patientId))
                    ThrowFault("PATIENT_NOT_FOUND", $"Patient {patientId} not found.");

                // Check for allergies
                var patient = PatientStore[patientId];
                if (patient.Allergies != null)
                {
                    foreach (var allergy in patient.Allergies)
                    {
                        if (medication.Name.IndexOf(allergy, StringComparison.OrdinalIgnoreCase) >= 0)
                        {
                            ThrowFault("ALLERGY_ALERT",
                                $"Patient has a documented allergy to {allergy}. Cannot prescribe {medication.Name}.");
                        }
                    }
                }
            }

            medication.IsActive = true;
            medication.StartDate = DateTime.UtcNow;

            _auditLogger.LogDataModification("PrescribeMedication", GetCallerIdentity(), transactionId,
                $"Prescribed {medication.Name} to patient {patientId}");

            return new HealthcareServiceResponse
            {
                Success = true,
                Message = $"Medication {medication.Name} prescribed successfully.",
                TransactionId = transactionId,
                Timestamp = DateTime.UtcNow,
                Errors = warnings
            };
        }
        catch (FaultException)
        {
            throw;
        }
        catch (Exception ex)
        {
            _auditLogger.LogError("PrescribeMedication", transactionId, ex.Message);
            ThrowFault("INTERNAL_ERROR", "An internal error occurred while prescribing medication.");
            return null;
        }
    }

